using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Set up options with the default reflection-based resolver
var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1) Strongly-typed metadata retrieval: GetTypeInfo<T>() returns JsonTypeInfo<T> directly
JsonTypeInfo<Person> personInfo = (JsonTypeInfo<Person>)options.GetTypeInfo(typeof(Person));
Console.WriteLine($"Got typed metadata for: {personInfo.Type.Name}");
Console.WriteLine($"  Kind: {personInfo.Kind}");
Console.WriteLine($"  Properties: {string.Join(", ", personInfo.Properties.Select(p => p.Name))}");

// Serialize using the typed metadata to prove it works
var alice = new Person("Alice", 30);
string json = JsonSerializer.Serialize(alice, personInfo);
Console.WriteLine($"  Serialized: {json}");

Console.WriteLine();

// 2) Probe without throwing: TryGetTypeInfo returns false instead of throwing
//    Use a resolver that only knows about Person, so Widget is unknown.
var limitedResolver = new DefaultJsonTypeInfoResolver();
var limitedOptions = new JsonSerializerOptions
{
    TypeInfoResolver = JsonTypeInfoResolver.Combine(
        new PersonOnlyResolver())
};

bool hasPerson = limitedOptions.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? maybePerson);
bool hasWidget = limitedOptions.TryGetTypeInfo(typeof(Widget), out JsonTypeInfo? maybeWidget);

Console.WriteLine($"TryGetTypeInfo(Person): {hasPerson} → {maybePerson?.Type.Name ?? "(null)"}");
Console.WriteLine($"TryGetTypeInfo(Widget): {hasWidget} → {maybeWidget?.Type.Name ?? "(null)"}");

// Records used in the demo
public record Person(string Name, int Age);
public record Widget(string Sku);

// A custom resolver that only provides metadata for Person
file class PersonOnlyResolver : IJsonTypeInfoResolver
{
    private readonly DefaultJsonTypeInfoResolver _inner = new();

    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options)
    {
        if (type == typeof(Person))
            return _inner.GetTypeInfo(type, options);
        return null; // signals "not available" — TryGetTypeInfo will return false
    }
}

